import { addCommonRoleOptions, commonRoleOptions } from './utils.js';
export const evalRole = {
    name: 'eval',
    options: { ...commonRoleOptions('eval') },
    body: {
        type: String,
        required: true,
    },
    run(data) {
        const node = { type: 'inlineExpression', value: data.body };
        addCommonRoleOptions(data, node);
        return [node];
    },
};
